examples.good:
@RestController
public class MyController {
  @GetMapping("/example")
  public ResponseEntity<String> getExample() {
    if (errorCondition) {
      return ResponseEntity.status(HttpStatus.BAD_REQUEST).body("error");
    }
    return ResponseEntity.ok("data");
  }
}
